/**
 * Errors that can occur in the mobile engine.
 */
sealed class MobileException(message: String): kotlin.Exception(message) {
        
        class NetworkException(message: String) : MobileException(message)
        
        class AuthenticationException(message: String) : MobileException(message)
        
        class RegistrationFailed(message: String) : MobileException(message)
        
        class CallFailed(message: String) : MobileException(message)
        
        class MediaException(message: String) : MobileException(message)
        
        class InvalidState(message: String) : MobileException(message)
        
        class GatewayException(message: String) : MobileException(message)
        
        class Timeout(message: String) : MobileException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<MobileException> {
        override fun lift(error_buf: RustBuffer.ByValue): MobileException = FfiConverterTypeMobileError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeMobileError : FfiConverterRustBuffer<MobileException> {
    override fun read(buf: ByteBuffer): MobileException {
        
            return when(buf.getInt()) {
            1 -> MobileException.NetworkException(FfiConverterString.read(buf))
            2 -> MobileException.AuthenticationException(FfiConverterString.read(buf))
            3 -> MobileException.RegistrationFailed(FfiConverterString.read(buf))
            4 -> MobileException.CallFailed(FfiConverterString.read(buf))
            5 -> MobileException.MediaException(FfiConverterString.read(buf))
            6 -> MobileException.InvalidState(FfiConverterString.read(buf))
            7 -> MobileException.GatewayException(FfiConverterString.read(buf))
            8 -> MobileException.Timeout(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: MobileException): ULong {
        return 4UL
    }

    override fun write(value: MobileException, buf: ByteBuffer) {
        when(value) {
            is MobileException.NetworkException -> {
                buf.putInt(1)
                Unit
            }
            is MobileException.AuthenticationException -> {
                buf.putInt(2)
                Unit
            }
            is MobileException.RegistrationFailed -> {
                buf.putInt(3)
                Unit
            }
            is MobileException.CallFailed -> {
                buf.putInt(4)
                Unit
            }
            is MobileException.MediaException -> {
                buf.putInt(5)
                Unit
            }
            is MobileException.InvalidState -> {
                buf.putInt(6)
                Unit
            }
            is MobileException.GatewayException -> {
                buf.putInt(7)
                Unit
            }
            is MobileException.Timeout -> {
                buf.putInt(8)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}





/**
 * Callback interface for receiving events from the Rust core.
 */
public interface MobileEventHandler {
    
    /**
     * Called when registration state changes.
     */
    fun `onRegistrationChanged`(`deviceId`: kotlin.String, `status`: kotlin.String, `error`: kotlin.String?)
    
    /**
     * Called when an incoming call arrives (via push notification).
     */
    fun `onIncomingCall`(`offer`: CallOffer)
    
    /**
     * Called when call state changes.
     */
    fun `onCallStateChanged`(`info`: CallInfo)
    
    /**
     * Called when media statistics are updated.
     */
    fun `onMediaStats`(`callId`: kotlin.String, `stats`: MediaStats)
    
    /**
     * Called when an error occurs.
     */
    fun `onError`(`context`: kotlin.String, `message`: kotlin.String)
    
    companion object
}

// Magic number for the Rust proxy to call using the same mechanism as every other method,
// to free the callback once it's dropped by Rust.
internal const val IDX_CALLBACK_FREE = 0
// Callback return codes
internal const val UNIFFI_CALLBACK_SUCCESS = 0
internal const val UNIFFI_CALLBACK_ERROR = 1
internal const val UNIFFI_CALLBACK_UNEXPECTED_ERROR = 2

/**
 * @suppress
 */
public abstract class FfiConverterCallbackInterface<CallbackInterface: Any>: FfiConverter<CallbackInterface, Long> {
    internal val handleMap = UniffiHandleMap<CallbackInterface>()

    internal fun drop(handle: Long) {
        handleMap.remove(handle)
    }

    override fun lift(value: Long): CallbackInterface {
        return handleMap.get(value)
    }

    override fun read(buf: ByteBuffer) = lift(buf.getLong())

    override fun lower(value: CallbackInterface) = handleMap.insert(value)

    override fun allocationSize(value: CallbackInterface) = 8UL

    override fun write(value: CallbackInterface, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}

